module RefModule (
    input [1:0] in,
    input sel,
    output reg out
);
  wire [1:0] _tap_in = in & {2{1'b1}};


    // Multiplexer logic
    always @(*) begin
        case (sel)
            1'b0: out = in[0];
            1'b1: out = in[1];
            default: out = 1'b0;
        endcase
    end

endmodule
